public void testFormatWithExplicitTimezone() throws Exception
    {
        ObjectMapper mapper = new ObjectMapper();
        mapper.setDateFormat(new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss"));
        mapper.setTimeZone(TimeZone.getTimeZone("UTC"));
        String json = mapper.writeValueAsString(new DateAsDefaultBeanWithTimezone(0L));
        assertEquals(aposToQuotes("{'date':'1970-01-01T00:00:00'}"), json);
    }

public void testFormatWithLocale() throws Exception
    {
        ObjectMapper mapper = new ObjectMapper();
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd", Locale.US);
        mapper.setDateFormat(sdf);
        String json = mapper.writeValueAsString(new DateAsDefaultBeanWithTimezone(0L));
        assertTrue(json.contains("1970-01-01"));
    }

public void testFormatWithDefaultSettings() throws Exception
    {
        ObjectMapper mapper = new ObjectMapper();
        mapper.setDateFormat(new SimpleDateFormat("dd/MM/yyyy"));
        String json = mapper.writeValueAsString(new DateAsDefaultBeanWithTimezone(86400000L));
        assertTrue(json.contains("02/01/1970") || json.contains("01/01/1970"));
    }
